public class Transpose {
    static int[][] transpose(int[][] m) {
        int[][] t = new int[m.length][m.length];   // bug: should be [m[0].length][m.length]
        for (int i = 0; i < m.length; i++)
            for (int j = 0; j < m[0].length; j++)
                t[j][i] = m[i][j];
        return t;
    }
}
